{"content":"package com.ichi2.anki

import android.content.Intent
import android.widget.ListView
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.testutils.AnkiAssert
import com.ichi2.testutils.AnkiAssert.assertDoesNotThrow
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.Robolectric
import org.robolectric.Shadows.shadowOf
import timber.log.Timber

@RunWith(AndroidJUnit4::class)
class CardBrowserSelectionTest : RobolectricTest() {

    @Test
    fun unselectingCardInMultiSelectModeWorks() {
        val browser = getBrowserWithNotes(3)

        // 1. Enter multi-select mode by long clicking the first item
        longClickItem(browser, 0)
        assertThat("Item 0 should be selected", browser.hasSelectedCardAtPosition(0), equalTo(true))
        assertThat("Browser should be in multi-select mode", browser.isInMultiSelectMode, equalTo(true))

        // 2. Select the second item by clicking it
        clickItem(browser, 1)
        assertThat("Item 1 should be selected", browser.hasSelectedCardAtPosition(1), equalTo(true))
        assertThat("Item 0 should still be selected", browser.hasSelectedCardAtPosition(0), equalTo(true))

        // 3. Unselect the first item by clicking it again
        clickItem(browser, 0)
        assertThat("Item 0 should be unselected", browser.hasSelectedCardAtPosition(0), equalTo(false))
        assertThat("Item 1 should still be selected", browser.hasSelectedCardAtPosition(1), equalTo(true))
    }

    private fun clickItem(browser: CardBrowser, position: Int) {
        val listView = browser.findViewById<ListView>(R.id.card_browser_list)
        val listener = listView.onItemClickListener
            ?: throw IllegalStateException("no item click listener found")

        // We don't strictly need the view for the listener logic in CardBrowser, 
        // but we should provide one if possible or mock it.
        // In CardBrowser.kt: val cb = view!!.findViewById<CheckBox>(R.id.card_checkbox)
        // So we need a view with a checkbox.

        val view = browser.cardsAdapter.getView(position, null, listView)

        listener.onItemClick(
            listView,
            view,
            position,
            listView.getItemIdAtPosition(position)
        )
        advanceRobolectricUiLooper()
    }

    private fun longClickItem(browser: CardBrowser, position: Int) {
        val listView = browser.findViewById<ListView>(R.id.card_browser_list)
        val listener = listView.onItemLongClickListener
            ?: throw IllegalStateException("no item long click listener found")

        val view = browser.cardsAdapter.getView(position, null, listView)

        listener.onItemLongClick(
            listView,
            view,
            position,
            listView.getItemIdAtPosition(position)
        )
        advanceRobolectricUiLooper()
    }

    private fun getBrowserWithNotes(noteCount: Int): CardBrowser {
        ensureCollectionLoadIsSynchronous()
        for (i in 0 until noteCount) {
            addNoteUsingBasicModel(i.toString(), "back")
        }
        return super.startRegularActivity<CardBrowser>(Intent()).also {
            advanceRobolectricUiLooper()
        }
    }
}
